var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"주변을 메우던 불길함이 사그라졌다.","JPN":"一帯を覆っていた不吉な気配が消えた。","ENG":"The ominous presence around us has faded.","TWN":"周圍彌漫的不祥氣息消散了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하늘이 원래대로 돌아온 걸 보면… 당장의 침식사태는 종식된 건가?","JPN":"空が元に戻ったということは……ひとまず侵食事態は収まったのか？","ENG":"If the sky has returned to normal... then maybe this Corruption disaster is over for now.","TWN":"看天空恢復正常的樣子……眼下的侵蝕事件是結束了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……읏.","JPN":"……っ。","ENG":"...Ngh.","TWN":"……呃。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이전에 난 상처가 다시 벌어졌나.","JPN":"この前の傷が、また開いたか。","ENG":"Has my old wound reopened?","TWN":"之前我的傷口又裂開了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"검의 날도… 해졌군. 역시 무구가 아닌 평범한 검으로는 한계가 있는 모양이야.","JPN":"刃も……鈍ってきた。やはり、武具でないただの剣では限界があるようだ。","ENG":"The blade's edge... is dull. I suppose an ordinary sword has its limits compared to an Armament.","TWN":"劍刃也變鈍了啊。果然普通的劍不是武器，還是有極限的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지쳤으니, 우선 마을로 돌아가서…….","JPN":"疲れた……まずは村へ戻って……。","ENG":"I'm exhausted. I should head back to the village and–","TWN":"累了，先回村子吧……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이런…! 설마, 얕게 베였던 건가?!","JPN":"しまった……！　まさか、斬りが浅かったのか！？","ENG":"What...?! Did I slash too shallow?!","TWN":"糟了……！難道是被輕輕劃傷了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"치잇!","JPN":"ちっ！","ENG":"Tch!","TWN":"嘖！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"찰나의 순간.","JPN":"刹那の瞬間。","ENG":"In a fleeting moment.","TWN":"刹那的瞬間。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"죽음을 앞둔 찰나의 순간, 인간은 시간이 느려지는 듯한 경험을 한다고 한다.","JPN":"死を目前にしたその瞬間、人は時の流れが遅くなる感覚を覚えるらしい。","ENG":"They say, at the moment before death, time seems to slow for humans.","TWN":"在瀕臨死亡的瞬間，人類會感受到時間彷彿變慢了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"한 마리가, 더 있었……!","JPN":"もう一体、いたのか……！","ENG":"There was... another–?!","TWN":"還有一隻……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그것이 시간의 짓궂음인지 마지막을 남기라는 신의 자비인지 알 수는 없으나.","JPN":"それが時の悪戯なのか、最期を遺させようという神の慈悲なのかはわからない。","ENG":"I do not know if it is time’s cruel jest or the gods’ mercy that I am allowed to leave something at the end.","TWN":"不知這是時間的捉弄，還是神的憐憫讓我們留到最後。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"소름 돋는 죽음의 예감이 몸을 스치고 지나감에, 또한 인간은 깨닫는다.","JPN":"体中の毛が逆立つような死の予感が走ったとき、人はまた思い知らされる。","ENG":"When the chilling touch of death brushes past, people realize...","TWN":"當毛骨悚然的死亡預感掠過身體時，人類也會意識到這一點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"정해진 죽음이라는 운명을, 그들은 결코 벗어날 수 없음을.","JPN":"定められた死という運命から、決して逃れられぬということを。","ENG":"That a fated death cannot be escaped.","TWN":"他們永遠無法逃脫既定的死亡命運。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"자세를 흐트러트리지 마시지요. 기사란 신체의 어느 곳도 허투루 쓰지 않는 법입니다.","JPN":"姿勢を崩さないでください。騎士とは、身体の一部たりとも無駄には使わぬものです。","ENG":"Don't break your stance. A knight never lets any part of their body go to waste.","TWN":"請保持姿勢不變。騎士絕不會浪費身體的任何部分。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_1"},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"무구란 그저 힘을 조율하는 매개체일 뿐. 중요한 건…….","JPN":"武具は、あくまで力を調整するための媒介に過ぎません。大切なのは……","ENG":"An Armament is only a conduit to channel power. What truly matters is...","TWN":"武器只是調節力量的媒介。重要的是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_2"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"그 안에 담긴 <color=#ffd34c>별빛</color>을 어떻게 다루느냐입니다.","JPN":"その中に宿る<color=#ffd34c>星の光</color>をどう扱うかです。","ENG":"How you wield the <color=#ffd34c>starlight</color> within.","TWN":"關鍵在於如何處理其中蘊含的<color=#ffd34c>星光</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_3"},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……!!","JPN":"……！！","ENG":"...!!","TWN":"……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"쓰러트린 건가?","JPN":"倒したのか？","ENG":"Is it dead?","TWN":"打倒了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"방금 그건…….","JPN":"今のは……","ENG":"What was that just now...?","TWN":"剛才那是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"겨우, 제 목소리가 닿았네요.","JPN":"ようやく、私の声が届きましたね。","ENG":"It seems my voice has finally reached you.","TWN":"終於，我的聲音傳到了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GRACE_PRIDE_NULL_NULL","text":{"KOREA":"늦지 않아서 다행이에요, 에스텔.","JPN":"間に合って良かったです、エステル。","ENG":"Good thing I wasn't too late, Esther.","TWN":"幸好沒來晚，艾斯特。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_PRIDE_NULL_NULL","text":{"KOREA":"오랜만… 아니, 여기서는 처음 뵙는다고 말하는 편이 나으려나요?","JPN":"お久しぶり……いえ、ここでははじめましてと言ったほうがいいかしら？","ENG":"Long time no see– Or maybe, \\"Nice to meet you\\" fits better in this context?","TWN":"好久不見…啊，還是說在這裡應該說初次見面呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_PRIDE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"에스텔이라니…….","JPN":"エステル……だと？","ENG":"Esther...?","TWN":"居然是艾斯特……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은… 대체…….","JPN":"あなたは……いったい……","ENG":"Who... are you...?","TWN":"你……到底……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"만약 인간이 죽음을 벗어나는 법이 있다면, 단 하나.","JPN":"もし人が死を逃れる術があるとするなら、それはただひとつ。","ENG":"If there's any way for humans to escape death, there's only one.","TWN":"如果人類有逃避死亡的方法，那就只有一個。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"신조차 예상치 못한 기연이 그 운명을 비트는 것이다.","JPN":"神ですら予見しえぬ奇縁が、その運命をねじ曲げるのだ。","ENG":"A miraculous twist of fate that even god never saw coming.","TWN":"連神也無法預料的奇緣扭轉了命運。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};